      const T xi      = x0(fi);
      const T Lx      = Lx_all(ix, fi);
      const T dLxi_v  = lipxi(fi);
      const T ddLxi_v = lipxi2(fi);
      // SymPy-derived closed forms for d^0/dx^0 of each HIP2 shape:
      dnf(ix, 3*fi + 0) = T(6)*pow(Lx, T(3))*pow(dLxi_v, T(2))*pow(xi, T(2)) - T(12)*pow(Lx, T(3))*pow(dLxi_v, T(2))*xi*xv + T(6)*pow(Lx, T(3))*pow(dLxi_v, T(2))*pow(xv, T(2)) + T(3)*pow(Lx, T(3))*dLxi_v*xi - T(3)*pow(Lx, T(3))*dLxi_v*xv - T(3)/T(2)*pow(Lx, T(3))*ddLxi_v*pow(xi, T(2)) + T(3)*pow(Lx, T(3))*ddLxi_v*xi*xv - T(3)/T(2)*pow(Lx, T(3))*ddLxi_v*pow(xv, T(2)) + pow(Lx, T(3));
      dnf(ix, 3*fi + 1) = -T(3)*pow(Lx, T(3))*dLxi_v*pow(xi, T(2)) + T(6)*pow(Lx, T(3))*dLxi_v*xi*xv - T(3)*pow(Lx, T(3))*dLxi_v*pow(xv, T(2)) - pow(Lx, T(3))*xi + pow(Lx, T(3))*xv;
      dnf(ix, 3*fi + 2) = (T(1)/T(2))*pow(Lx, T(3))*pow(xi, T(2)) - pow(Lx, T(3))*xi*xv + (T(1)/T(2))*pow(Lx, T(3))*pow(xv, T(2));
      dnf(ix, 3*fi + 1) *= element_length;
