      dnf(ix, 3*fi + 1) = T(6)*pow(Lx, T(3))*dLxi_v*xi - T(6)*pow(Lx, T(3))*dLxi_v*xv + pow(Lx, T(3)) - T(9)*pow(Lx, T(2))*dLx*dLxi_v*pow(xi, T(2)) + T(18)*pow(Lx, T(2))*dLx*dLxi_v*xi*xv - T(9)*pow(Lx, T(2))*dLx*dLxi_v*pow(xv, T(2)) - T(3)*pow(Lx, T(2))*dLx*xi + T(3)*pow(Lx, T(2))*dLx*xv;
