      dnf(ix, 3*fi + 1) = -T(6)*pow(Lx, T(3))*dLxi_v + T(36)*pow(Lx, T(2))*dLx*dLxi_v*xi - T(36)*pow(Lx, T(2))*dLx*dLxi_v*xv + T(6)*pow(Lx, T(2))*dLx - T(9)*pow(Lx, T(2))*dLxi_v*ddLx*pow(xi, T(2)) + T(18)*pow(Lx, T(2))*dLxi_v*ddLx*xi*xv - T(9)*pow(Lx, T(2))*dLxi_v*ddLx*pow(xv, T(2)) - T(3)*pow(Lx, T(2))*ddLx*xi + T(3)*pow(Lx, T(2))*ddLx*xv - T(18)*Lx*pow(dLx, T(2))*dLxi_v*pow(xi, T(2)) + T(36)*Lx*pow(dLx, T(2))*dLxi_v*xi*xv - T(18)*Lx*pow(dLx, T(2))*dLxi_v*pow(xv, T(2)) - T(6)*Lx*pow(dLx, T(2))*xi + T(6)*Lx*pow(dLx, T(2))*xv;
